import { useNavigate } from "react-router-dom";
import { Button } from "../components/atoms";

export default function Login() {
  const navigate = useNavigate();

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: '#f4f7f6' }}>
      <div style={{ textAlign: 'center', padding: '3rem', background: 'white', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h1 style={{ marginBottom: '2rem', fontSize: '2rem', color: '#333' }}>Bienvenido a Cafesito</h1>
        <Button 
          variant="primary" 
          size="lg" 
          onClick={() => navigate('/empleado', { replace: true })}
          style={{ padding: '1rem 3rem', fontSize: '1.25rem' }}
        >
          Empezar
        </Button>
      </div>
    </div>
  );
}
